  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">BitPay's MiCA Passport — One License, 27 Markets</text>
  <g font-family="sans-serif">
    <circle cx="170" cy="200" r="110" fill="none" stroke="#3f3f46" stroke-width="2" stroke-dasharray="4,5"/>
    <circle cx="170" cy="200" r="60" fill="#06b6d4" fill-opacity="0.9"/>
